INSERT INTO public.cards (topic_set_id, order_index, question, answer) VALUES
('11111111-1111-1111-1111-111111111111', 26, 'What is Industrial Automation?', 'Industrial automation is the use of various control systems (computers, robots, controllers) to operate processes and machinery in manufacturing with improved precision, efficiency, and safety. It replaces human intervention with automated systems.'),
('11111111-1111-1111-1111-111111111111', 27, 'Name six benefits of Industrial Automation.', '1) Minimization of human error. 2) Reduced production costs. 3) Efficient inventory management. 4) Real-time monitoring and predictive maintenance. 5) Enhanced product quality and consistency. 6) Improved workplace safety.'),
('11111111-1111-1111-1111-111111111111', 28, 'What is a Programmable Logic Controller (PLC)?', 'A rugged industrial computer designed to control manufacturing processes using ladder logic or other programming languages. It processes inputs from sensors and produces outputs to actuators. PLCs are known for reliability, ease of troubleshooting, and modular design.'),
('11111111-1111-1111-1111-111111111111', 29, 'Give an example of a PLC application.', 'Example: Controlling an assembly line in car manufacturing where a PLC coordinates robotic welders, parts handling, and quality checks.'),
('11111111-1111-1111-1111-111111111111', 30, 'What is SCADA?', 'Supervisory Control and Data Acquisition. A system that provides real-time data collection and control from remote geographical locations. It integrates sensor data, process control, and historical data logging with graphical interfaces for operators. Example: Managing water treatment plants.'),
('11111111-1111-1111-1111-111111111111', 31, 'What is a Distributed Control System (DCS)?', 'A system using a network of controllers distributed throughout an industrial plant. Each controller handles a segment of the process. DCS increases reliability and allows sophisticated control strategies in large-scale continuous processes. Example: Chemical processing in refineries.'),
('11111111-1111-1111-1111-111111111111', 32, 'What is Direct Digital Control (DDC)?', 'A control method where digital processors execute control algorithms directly on real-time process data. Commonly used in building management systems for precise control of heaters, air conditioning, and lighting.'),
('11111111-1111-1111-1111-111111111111', 33, 'What is a Human-Machine Interface (HMI)?', 'A graphical dashboard that allows operators to monitor system performance, view alarms, and input commands. It is the critical link between the human operator and automated equipment. Example: Touchscreen panels displaying data trends and system status.'),
('11111111-1111-1111-1111-111111111111', 34, 'What is a PID Controller?', 'A control loop feedback mechanism widely used in industrial control systems. It continuously calculates error between desired setpoint and measured variable, applying corrective control through proportional, integral, and derivative adjustments. Example: Temperature control in an oven.'),
('11111111-1111-1111-1111-111111111111', 35, 'What is an Actuator?', 'A device that converts control signals into physical motion. Depending on energy source, actuators may be electrical, hydraulic, or pneumatic. They are essential for moving robotic arms or operating valves.'),
('11111111-1111-1111-1111-111111111111', 36, 'What is a Transducer?', 'A device that converts one form of energy into another. In automation, it transforms physical signals (pressure, temperature) into electrical signals readable by PLCs or controllers. Example: A thermocouple converting heat into voltage.'),
('11111111-1111-1111-1111-111111111111', 37, 'What are Industrial Protocols?', 'Rules that define communication between devices in industrial networks. Standard protocols ensure sensors, controllers, and actuators exchange data reliably. Examples: Modbus, Ethernet/IP, Profibus, EtherCAT, ControlNet.'),
('11111111-1111-1111-1111-111111111111', 38, 'What is Computer Numerical Control (CNC)?', 'Computers controlling machine tools through preprogrammed sequences. CNC systems are critical for high-precision tasks like cutting, drilling, and milling. Widely used in manufacturing.'),
('11111111-1111-1111-1111-111111111111', 39, 'What is Motion Control?', 'Strategies and devices that manage machine movement. Includes controlling speed, position, and acceleration of motors and drives in automated systems.'),
('11111111-1111-1111-1111-111111111111', 40, 'What is Adaptive Control?', 'Control systems that adjust parameters in real time to respond to changing conditions. This ensures optimal performance when process dynamics shift.'),
('11111111-1111-1111-1111-111111111111', 41, 'What is a Sensor?', 'A device that detects environmental changes (temperature, pressure, light) and converts them into electrical signals for processing. Sensors serve as the eyes and ears in automation, providing feedback for system control.'),
('11111111-1111-1111-1111-111111111111', 42, 'What is Robotics?', 'The integration of mechanical systems, sensors, and controllers to perform tasks automatically. Robots are used in assembly, material handling, and precision manufacturing tasks.'),
('11111111-1111-1111-1111-111111111111', 43, 'What is a Fieldbus?', 'A digital, bi-directional communication network connecting sensors, actuators, and controllers in industrial settings. It supports real-time data exchange and replaces traditional point-to-point wiring.'),
('11111111-1111-1111-1111-111111111111', 44, 'What is Ethernet in industrial applications?', 'High-speed wired networking increasingly used in industrial settings to integrate control systems with broader enterprise networks. Enables real-time communication and data integration.'),
('11111111-1111-1111-1111-111111111111', 45, 'What is Industrial Internet of Things (IIoT)?', 'Extends internet connectivity to industrial devices, allowing enhanced monitoring, data analytics, and predictive maintenance. IIoT networks optimize production and decrease downtime through real-time data exchange.'),
('11111111-1111-1111-1111-111111111111', 46, 'What is a Process Flow Diagram (PFD)?', 'A graphical representation showing the flow of materials and energy in a process. It clarifies how different components interact within an industrial system.'),
('11111111-1111-1111-1111-111111111111', 47, 'What is a Servo Motor?', 'A motor offering precise control of angular position and speed. It combines a motor with a feedback sensor. Fundamental in robotic arms, CNC machines, and precision positioning applications.'),
('11111111-1111-1111-1111-111111111111', 48, 'What is Synchronous Serial Interface (SSI)?', 'A protocol for communication between encoders (position sensors) and controllers. Provides accurate position data in real time for precision control applications.'),
('11111111-1111-1111-1111-111111111111', 49, 'What is a Variable Frequency Drive (VFD)?', 'A device that adjusts AC motor speed by varying frequency and voltage supplied. Essential in applications where motor speed regulation improves energy efficiency and process control.'),
('11111111-1111-1111-1111-111111111111', 50, 'What is a Wide Area Network (WAN)?', 'A network connecting various local networks over large geographical areas. In industrial applications, WANs enable remote monitoring and control of facilities dispersed across multiple locations.'),
('11111111-1111-1111-1111-111111111111', 51, 'Define Fixed Automation.', 'A production system where machines operate in a fixed sequence. Characteristics: high initial investment, extremely high production rates, inflexible for changing product types. Example: Automotive body welding stations.'),
('11111111-1111-1111-1111-111111111111', 52, 'Define Programmable Automation.', 'Systems using programmable controllers to change operation sequences between production runs. Characteristics: moderate flexibility, suitable for batch production, lower initial cost than fixed systems. Example: CNC machines reprogrammed for different parts.'),
('11111111-1111-1111-1111-111111111111', 53, 'Define Flexible Automation.', 'Systems designed to easily accommodate production process changes. Characteristics: high flexibility, suitable for low- to medium-volume production varieties. Example: Robot cells switching between assembly of different models via software updates.'),
('11111111-1111-1111-1111-111111111111', 54, 'Define Integrated Automation.', 'All production stages (planning, scheduling, execution, quality control) are interconnected. Characteristics: seamless data flow, real-time adjustments based on production information. Example: Smart factory with MES and ERP systems communicating instantaneously.'),
('11111111-1111-1111-1111-111111111111', 55, 'List three types of Temperature Sensors.', '1) Thermocouples: detect heat levels and convert temperature differences into voltage signals. 2) Thermistors: resistance changes with temperature. 3) Resistance temperature detectors (RTD): use resistance change for accurate temperature measurement.'),
('11111111-1111-1111-1111-111111111111', 56, 'List three types of Pressure Sensors.', '1) Piezoelectric: use piezoelectric effect. 2) Strain gauge: measure pressure-induced deformation. 3) Capacitive: measure capacitance change proportional to pressure.'),
('11111111-1111-1111-1111-111111111111', 57, 'What is a Photoelectric Sensor?', 'Detects the presence or absence of objects by measuring light intensity. Types include diffuse (senses objects), retroreflective (uses reflector), and through-beam (light curtain style).'),
('11111111-1111-1111-1111-111111111111', 58, 'What is a Load Cell?', 'A transducer that converts force into electrical output. Used in weighing systems and force measurement applications.'),
('11111111-1111-1111-1111-111111111111', 59, 'What is an LVDT?', 'Linear Variable Differential Transformer. Converts linear displacement into a measurable electrical signal. Used in position measurement and control systems.'),
('11111111-1111-1111-1111-111111111111', 60, 'List three types of Electric Motors.', '1) DC Motors: simple control, used in adjustable speed applications. 2) AC Induction Motors: robust, high efficiency, fixed speed. 3) Stepper Motors: precise angular positioning in increments. 4) Servo Motors: precise speed and position control.'),
('11111111-1111-1111-1111-111111111111', 61, 'What is a Hydraulic Actuator?', 'Uses pressurized fluid (oil) to produce high force outputs. Ideal for heavy-duty applications requiring strong force and smooth motion. Common in hydraulic presses and heavy machinery.'),
('11111111-1111-1111-1111-111111111111', 62, 'What is a Pneumatic Actuator?', 'Uses compressed air to produce motion. Faster response than hydraulic actuators, simpler, but lower force. Used in rapid cycling applications and assembly machines.'),
('11111111-1111-1111-1111-111111111111', 63, 'What is an Encoder?', 'A transducer that converts rotational position or motion into a digital signal. Types: incremental (relative position) or absolute (exact position). Used in motor control and position feedback.'),
('11111111-1111-1111-1111-111111111111', 64, 'What is the Laplace Transform?', 'A mathematical tool converting time-domain functions f(t) into frequency-domain functions F(s) = ∫[0,∞] f(t)e^(-st) dt. Essential for solving differential equations in control systems.'),
('11111111-1111-1111-1111-111111111111', 65, 'State the Laplace Transform of e^(-at).', 'L{e^(-at)} = 1/(s+a), where s > -a.'),
('11111111-1111-1111-1111-111111111111', 66, 'State the Laplace Transform of sin(ωt).', 'L{sin(ωt)} = ω/(s^2 + ω^2), where s > 0.'),
('11111111-1111-1111-1111-111111111111', 67, 'State the Laplace Transform of cos(ωt).', 'L{cos(ωt)} = s/(s^2 + ω^2), where s > 0.'),
('11111111-1111-1111-1111-111111111111', 68, 'State the Laplace Transform of the derivative f''(t).', 'L{f''(t)} = sF(s) - f(0).'),
('11111111-1111-1111-1111-111111111111', 69, 'State the Laplace Transform of the second derivative f''''(t).', 'L{f''''(t)} = s^2 F(s) - sf(0) - f''(0).'),
('11111111-1111-1111-1111-111111111111', 70, 'What is the Inverse Laplace Transform?', 'The operation converting a frequency-domain function F(s) back to its time-domain representation f(t). Denoted as f(t) = L^(-1){F(s)}.'),
('11111111-1111-1111-1111-111111111111', 71, 'What is Partial Fraction Decomposition (PFD)?', 'A technique breaking down a complex rational function into simpler fractions. This allows easier inverse Laplace transformation of complex expressions.'),
('11111111-1111-1111-1111-111111111111', 72, 'Describe the Cover-up Method for PFD.', 'For distinct poles, to find coefficient A in the fraction A/(s-p), multiply both sides by (s-p) and substitute s=p. Useful for quick calculation of single poles in PFD.'),
('11111111-1111-1111-1111-111111111111', 73, 'What is a Pole in a Transfer Function?', 'A value of s that makes the denominator zero, causing the function to approach infinity. Poles determine system stability and transient response characteristics.'),
('11111111-1111-1111-1111-111111111111', 74, 'What is a Zero in a Transfer Function?', 'A value of s that makes the numerator zero, causing the function to equal zero. Zeros affect system response, phase, and magnitude characteristics.'),
('11311111-1111-1111-1111-111111111111', 75, 'What is Transfer Function G(s)?', 'The Laplace transform ratio of output to input: G(s) = Y(s)/U(s) for zero initial conditions. It characterizes the input-output behavior of a linear system.'),
('11111111-1111-1111-1111-111111111111', 76, 'What is a First-Order System?', 'A system described by a first-order differential equation with transfer function G(s) = K/(τs + 1). Time constant τ determines response speed. Example: RC circuit.'),
('11111111-1111-1111-1111-111111111111', 77, 'What is a Second-Order System?', 'A system described by a second-order differential equation with transfer function G(s) = ωn^2/(s^2 + 2ζωn·s + ωn^2). ωn is natural frequency, ζ is damping ratio.'),
('11111111-1111-1111-1111-111111111111', 78, 'What is the Damping Ratio (ζ)?', 'A dimensionless parameter describing how oscillations decay in a second-order system. ζ<1 = underdamped (oscillatory), ζ=1 = critically damped, ζ>1 = overdamped (slow response).'),
('11111111-1111-1111-1111-111111111111', 79, 'What is Natural Frequency (ωn)?', 'The frequency at which a system oscillates freely without damping. Expressed in rad/s. Higher ωn means faster response.'),
('11111111-1111-1111-1111-111111111111', 80, 'Define Peak Time (Tp) for a second-order system.', 'The time at which the step response reaches its maximum value. Formula: Tp = π/ωd where ωd = ωn√(1-ζ^2) is the damped frequency.'),
('11111111-1111-1111-1111-111111111111', 81, 'Define Maximum Overshoot (Mp) for a second-order system.', 'The percentage by which the response exceeds the final value. Formula: Mp = e^(-πζ/√(1-ζ^2)) × 100%.'),
('11111111-1111-1111-1111-111111111111', 82, 'Define Settling Time (Ts) for a second-order system.', 'Time for the response to reach and stay within a certain band (usually 2% or 5%) of the final value. Formula: Ts ≈ 4/(ζωn) for 2% criterion.'),
('11111111-1111-1111-1111-111111111111', 83, 'What is Steady-State Error?', 'The difference between desired and actual output as t approaches infinity. Indicates system accuracy. Lower steady-state error means better tracking.'),
('11111111-1111-1111-1111-111111111111', 84, 'What are the Three Input Signals in Control Systems?', '1) Setpoint (reference input): desired value of controlled variable. 2) Feedback signal: measured actual value for comparison. 3) Disturbance input: unwanted external influence affecting output.'),
('11111111-1111-1111-1111-111111111111', 85, 'What is a Step Response?', 'The system output when a unit step input u(t) = 1 (t > 0) is applied. Used to characterize system dynamics and stability. Graphically shows settling behavior.'),
('11111111-1111-1111-1111-111111111111', 86, 'What is Ramp Response?', 'The system output when a ramp input r(t) = t·u(t) is applied. Useful for evaluating how the system tracks slowly changing signals.'),
('11111111-1111-1111-1111-111111111111', 87, 'What is a Pole-Zero Diagram?', 'A graphical representation of poles and zeros in the s-plane. Poles shown as X, zeros as O. Helps visualize system stability and dominant response characteristics.'),
('11111111-1111-1111-1111-111111111111', 88, 'How do poles affect system stability?', 'Poles in the left-half plane (LHP) give stable systems. Poles on the imaginary axis: marginally stable. Poles in the right-half plane (RHP): unstable. Pole location directly determines transient response speed.'),
('11111111-1111-1111-1111-111111111111', 89, 'What is the Routh-Hurwitz Criterion?', 'An algebraic method to determine the number of closed-loop poles in the right-half plane without calculating poles explicitly. Used to assess stability without solving characteristic equations.'),
('11111111-1111-1111-1111-111111111111', 90, 'What is a Bode Plot?', 'Graphical representation of frequency response with two plots: magnitude (dB) vs. log frequency and phase (degrees) vs. log frequency. Used for stability analysis and controller design.'),
('11111111-1111-1111-1111-111111111111', 91, 'What is Gain Margin (GM)?', 'The factor by which gain can increase before the closed-loop system becomes unstable. Found at the phase crossover frequency where phase = -180 degrees. GM > 0 dB indicates stability.'),
('11111111-1111-1111-1111-111111111111', 92, 'What is Phase Margin (PM)?', 'The additional phase lag at the gain crossover frequency (where magnitude = 0 dB) that can be tolerated before instability. PM = 180 degrees + phase at ωgc. PM > 0 indicates stability.'),
('11111111-1111-1111-1111-111111111111', 93, 'What is the Nyquist Criterion?', 'A graphical method to assess closed-loop stability based on open-loop frequency response. Stable if the Nyquist plot does not encircle the critical point (-1, 0) for stable open-loop systems.'),
('11111111-1111-1111-1111-111111111111', 94, 'What are Corner Frequencies in Bode Plots?', 'Frequencies where the slope of magnitude plot changes (at poles and zeros). At a corner, magnitude changes by 20 dB/decade per pole/zero. Essential for constructing asymptotic Bode plots.'),
('11111111-1111-1111-1111-111111111111', 95, 'What is an Asymptotic Bode Plot?', 'An approximation of Bode magnitude plot using straight line segments between corner frequencies. Simplifies hand sketching and provides intuitive understanding of frequency response.'),
('11111111-1111-1111-1111-111111111111', 96, 'What is System Bandwidth?', 'The frequency range over which the system can respond effectively. Typically defined at -3 dB point. Larger bandwidth means faster transient response.'),
('11111111-1111-1111-1111-111111111111', 97, 'What is Rise Time (Tr)?', 'Time for step response to rise from 10% to 90% of final value. Lower rise time indicates faster response. For first-order systems: Tr ≈ 2.2τ.'),
('11111111-1111-1111-1111-111111111111', 98, 'Explain Feedback in Control Systems.', 'Feedback compares output with desired input, computing error signal. This error is used to adjust control signal, reducing deviation. Negative feedback improves stability and tracking. Positive feedback can cause instability.'),
('11111111-1111-1111-1111-111111111111', 99, 'What is Open-Loop Control?', 'Control without feedback. Controller applies predetermined action regardless of actual output. Simple but inaccurate, used when disturbances are minimal. Example: washing machine timer.'),
('11111111-1111-1111-1111-111111111111', 100, 'What is Closed-Loop Control?', 'Control with continuous feedback. System adjusts automatically to maintain desired output. More accurate, can reject disturbances, but more complex. Example: cruise control, thermostat.'),
('11111111-1111-1111-1111-111111111111', 101, 'What is a Transfer Function Matrix?', 'For multiple-input multiple-output (MIMO) systems, a matrix G(s) where each element Gij(s) represents transfer function from input j to output i. Used in analyzing coupled, multivariable systems.'),
('11111111-1111-1111-1111-111111111111', 102, 'What is System Coupling?', 'When outputs of one subsystem affect inputs of another subsystem. Decoupling techniques are used to simplify control of coupled systems.'),
('11111111-1111-1111-1111-111111111111', 103, 'What is Bode Plot Magnitude in dB?', 'Magnitude M in decibels = 20 log10(M). A magnitude of 2 = 6 dB, 10 = 20 dB. Logarithmic scale allows wide frequency range visualization.'),
('11111111-1111-1111-1111-111111111111', 104, 'List PLC Advantages over Relay Logic.', '1) Reprogrammability: change logic via software. 2) Reduced wiring complexity. 3) Built-in diagnostics and error codes. 4) Smaller space and weight. 5) Faster response times.'),
('11111111-1111-1111-1111-111111111111', 105, 'List PLC Disadvantages.', '1) Initial cost. 2) Training requirements for programming and maintenance. 3) Limited processing power vs general-purpose computers for complex algorithms.'),
('11111111-1111-1111-1111-111111111111', 106, 'What is Ladder Logic?', 'A graphical programming language for PLCs using symbols resembling electrical ladder circuits. Vertical lines are power rails, horizontal rungs contain logic elements (contacts, coils).'),
('11111111-1111-1111-1111-111111111111', 107, 'What is Function Block Diagram (FBD)?', 'A graphical programming language using interconnected function blocks to represent logic, control functions, and data flow. Alternative to ladder logic for PLC programming.'),
('11111111-1111-1111-1111-111111111111', 108, 'What is Structured Text (ST)?', 'A text-based high-level programming language for PLCs, similar to Pascal. Allows complex algorithms and mathematical operations. More powerful than ladder logic for advanced control.'),
('11111111-1111-1111-1111-111111111111', 109, 'What is Sequential Function Chart (SFC)?', 'A graphical programming language showing process steps and transitions. Each step contains actions, transitions have conditions. Used for sequential control applications.'),
('11111111-1111-1111-1111-111111111111', 110, 'What is a PLC Scan Cycle?', 'The repeating cycle of: 1) Read all inputs. 2) Execute user program. 3) Write outputs. 4) Perform diagnostics. Typical scan time: 10-100 milliseconds.'),
('11111111-1111-1111-1111-111111111111', 111, 'What is Real-Time Control?', 'Control system responding within guaranteed time limits. Critical for safety-related systems and applications like robotics, where timing is essential.'),
('11111111-1111-1111-1111-111111111111', 112, 'What is Hysteresis in Control?', 'A feature where switching occurs at different thresholds depending on direction of change. Example: thermostat turns on at 68 degrees but off at 72 degrees. Prevents rapid on-off cycling.'),
('11111111-1111-1111-1111-111111111111', 113, 'What is Error Correction in Control Systems?', 'Mechanisms to detect and correct deviations from desired setpoint. Proportional, integral, and derivative actions each contribute to error correction differently.'),
('11111111-1111-1111-1111-111111111111', 114, 'Describe the Final Value Theorem.', 'States that the steady-state value of f(t) as t approaches infinity equals the limit of s·F(s) as s approaches 0. Formula: lim(t→∞) f(t) = lim(s→0) s·F(s). Used to find steady-state error without solving differential equations.'),
('11111111-1111-1111-1111-111111111111', 115, 'What is Initial Value Theorem?', 'States that the initial value of f(t) at t=0 equals the limit of s·F(s) as s approaches infinity. Formula: f(0) = lim(s→∞) s·F(s). Useful for initial condition verification.'),
('11111111-1111-1111-1111-111111111111', 116, 'What is System Responsiveness?', 'The quickness of system output change in response to input change. Measured by rise time and settling time. Faster responsiveness means shorter transient period.'),
('11111111-1111-1111-1111-111111111111', 117, 'What is Signal Attenuation?', 'Reduction in signal magnitude as it passes through a system. Expressed as magnitude less than 1 or negative dB. Higher frequencies often experience greater attenuation.'),
('11111111-1111-1111-1111-111111111111', 118, 'What is System Bandwidth and why is it important?', 'Frequency range where system can effectively process signals (typically -3dB points). Important because it determines maximum signal frequency that can be tracked without significant attenuation.'),
('11111111-1111-1111-1111-111111111111', 119, 'What is Dead Zone?', 'A range of input values over which the system produces no output. Used to prevent response to small noise but can cause tracking errors. Important in actuator design.'),
('11111111-1111-1111-1111-111111111111', 120, 'What is Actuator Saturation?', 'When the actuator reaches its maximum output limit and cannot produce greater force or motion. Causes system nonlinearity and limits control effectiveness.'),
('11111111-1111-1111-1111-111111111111', 121, 'What is System Order?', 'The order of the highest derivative in the system differential equation. First-order: one energy storage. Second-order: two energy storages. Higher order = more complex dynamics.'),
('11111111-1111-1111-1111-111111111111', 122, 'What is a System Impulse Response?', 'The system output when an impulse (Dirac delta) input δ(t) is applied. The impulse response h(t) completely characterizes the linear time-invariant system.'),
('11111111-1111-1111-1111-111111111111', 123, 'What is Convolution in System Analysis?', 'A mathematical operation that relates input, system impulse response, and output: y(t) = ∫u(τ)h(t-τ) dτ. In Laplace domain: Y(s) = U(s)·H(s).'),
('11111111-1111-1111-1111-111111111111', 124, 'What is Frequency Response?', 'The steady-state response of a system to sinusoidal input at various frequencies. Characterized by magnitude and phase vs. frequency. Foundation for Bode and Nyquist analysis.'),
('11111111-1111-1111-1111-111111111111', 125, 'What is Phase Lag?', 'The time delay between input and output sinusoids, expressed as negative phase angle. More phase lag indicates longer system response time. Critical for stability analysis.'),
('11111111-1111-1111-1111-111111111111', 126, 'Define the Steady-State Gain.', 'The ratio of output to input in steady state for a DC input. For G(s), steady-state gain = G(0). Indicates how much the system amplifies or attenuates constant inputs.'),
('11111111-1111-1111-1111-111111111111', 127, 'What is Linearity in Control Systems?', 'A system is linear if it satisfies superposition: response to sum of inputs equals sum of individual responses. Simplifies analysis using Laplace and frequency response methods.'),
('11111111-1111-1111-1111-111111111111', 128, 'What is Time-Invariance?', 'A system is time-invariant if its behavior does not change with time. If input is delayed by time τ, output is also delayed by τ. Allows use of Laplace methods.'),
('11111111-1111-1111-1111-111111111111', 129, 'What is System Causality?', 'A system is causal if output depends only on present and past inputs, never on future inputs. All physical systems are causal.'),
('11111111-1111-1111-1111-111111111111', 130, 'What is a State-Space Representation?', 'Represents a system using first-order differential equations: x_dot = Ax + Bu, y = Cx + Du. x = state vector, u = input, y = output. Alternative to transfer function representation.'),
('11111111-1111-1111-1111-111111111111', 131, 'What is System Observability?', 'The ability to determine internal states from output measurements. Observable systems allow full state feedback design.'),
('11111111-1111-1111-1111-111111111111', 132, 'What is System Controllability?', 'The ability to drive any state to any desired value using appropriate inputs. Controllable systems allow full-state feedback control design.'),
('11111111-1111-1111-1111-111111111111', 133, 'What is Characteristic Equation?', 'For closed-loop system, det(sI - A) = 0 in state space or 1 + G(s)H(s) = 0 for transfer function systems. Roots are closed-loop poles determining stability.'),
('11111111-1111-1111-1111-111111111111', 134, 'What is Sensitivity in Control?', 'Measure of how system output changes with parameter variations. Low sensitivity is desirable (robust design). Expressed as ratio of percentage output change to percentage parameter change.'),
('11111111-1111-1111-1111-111111111111', 135, 'What is Disturbance Rejection?', 'The ability of a control system to counteract the effects of unwanted external disturbances. Feedback improves disturbance rejection compared to open-loop control.');
INSERT INTO public.cards (topic_set_id, order_index, question, answer) VALUES
('22222222-2222-2222-2222-222222222222', 16, 'What is an Integrator in Control?', 'A controller that outputs the integral of error over time. Transfer function: Gi(s) = Ki/s. Eliminates steady-state error for constant disturbances. Slow initial response.'),
('22222222-2222-2222-2222-222222222222', 17, 'What is a Differentiator in Control?', 'A controller that outputs the derivative of error. Transfer function: Gd(s) = Kd·s. Improves transient response and damping. Amplifies high-frequency noise.'),
('22222222-2222-2222-2222-222222222222', 18, 'How do Proportional, Integral, and Derivative terms interact in PID?', 'P term: responds to current error. I term: corrects cumulative error (steady-state). D term: anticipates future error and dampens response. Combined they provide fast, accurate, stable control.'),
('22222222-2222-2222-2222-222222222222', 19, 'What is Integral Windup in PID Control?', 'The integral term accumulating large values when error is large (e.g., during startup or disturbance). Causes excessive overshoot and slow recovery. Prevention: limit integral sum or use anti-windup schemes.'),
('22222222-2222-2222-2222-222222222222', 20, 'What is PD Control and when is it used?', 'Transfer function: Gc(s) = Kp + Kd·s. No integral term. Improves transient response and adds damping. Does NOT eliminate steady-state error. Used in servo systems, position control.'),
('22222222-2222-2222-2222-222222222222', 21, 'What is PI Control and when is it used?', 'Transfer function: Gc(s) = Kp + Ki/s. No derivative term. Eliminates steady-state error without derivative noise. Slower transient response. Used in temperature and flow control.'),
('22222222-2222-2222-2222-222222222222', 22, 'What is the Ziegler-Nichols Method?', 'An empirical tuning method for PID controllers. Set Ki=Kd=0, increase Kp until oscillation, measure period Pu and gain Ku. Then set: Kp=0.6Ku, Ti=Pu/2, Td=Pu/8.'),
('22222222-2222-2222-2222-222222222222', 23, 'What is Parallel Form of PID?', 'Transfer function: u(t) = Kp·e(t) + Ki·∫e dt + Kd·de/dt or Gc(s) = Kp + Ki/s + Kd·s. Most common industrial form. Parameters are independent.'),
('22222222-2222-2222-2222-222222222222', 24, 'What is Series Form of PID?', 'Transfer function: Gc(s) = Kc(1 + 1/τI·s)(1 + τD·s). Proportional gain Kc multiplies all terms. Integration and derivative time constants τI and τD.'),
('22222222-2222-2222-2222-222222222222', 25, 'What is Derivative Kick in PID?', 'Sudden large output spike when setpoint changes, caused by derivative of setpoint. Prevention: differentiate error, not setpoint, or use low-pass filter.'),
('22222222-2222-2222-2222-222222222222', 26, 'What is Temperature Compensation in PID?', 'Adjustment of PID gains based on operating temperature changes. Critical in temperature-sensitive processes like chemical reactors.'),
('22222222-2222-2222-2222-222222222222', 27, 'What is Cascade Control Strategy?', 'Two controllers: outer (master) generates setpoint for inner (slave). Inner controller responds faster to disturbances. Used when system has slow and fast dynamics. Improves setpoint tracking and disturbance rejection.'),
('22222222-2222-2222-2222-222222222222', 28, 'What is Ratio Control?', 'Maintains constant ratio between two process variables. Wild stream uncontrolled, controlled stream adjusted to maintain ratio. Example: fuel-to-air ratio in combustion.'),
('22222222-2222-2222-2222-222222222222', 29, 'What is Feedforward Control?', 'Adjusts manipulated variable based on predicted disturbance, not measured error. Faster response than feedback. Requires disturbance measurement and system model.'),
('22222222-2222-2222-2222-222222222222', 30, 'Compare Feedforward vs Feedback Control.', 'Feedforward: proactive, fast, requires disturbance measurement. Feedback: reactive, addresses unmeasured disturbances, always stabilizes linear systems. Optimal solution combines both.'),
('22222222-2222-2222-2222-222222222222', 31, 'What is Servo vs Regulatory Control?', 'Servo: tracks changing setpoint. Regulatory: maintains constant setpoint against disturbances. Different performance measures: servo emphasizes tracking, regulatory emphasizes disturbance rejection.'),
('22222222-2222-2222-2222-222222222222', 32, 'What is Smith Predictor?', 'Advanced control technique for systems with large dead time. Uses model to predict future output, compensates for delay. Improves response for high dead-time systems.'),
('22222222-2222-2222-2222-222222222222', 33, 'What is Dead Time (Transport Lag)?', 'Time delay between input change and output response. Common in conveyor systems, pipelines. Reduces system stability margin and complicates control.'),
('22222222-2222-2222-2222-222222222222', 34, 'What is a Manipulated Variable?', 'The control output adjusted by the controller to achieve desired process output. Example: valve opening, motor speed.'),
('22222222-2222-2222-2222-222222222222', 35, 'What is a Measured Variable?', 'Process output measured by sensor, fed back to controller for comparison with setpoint.'),
('22222222-2222-2222-2222-222222222222', 36, 'What is Process Model?', 'Mathematical description of how process inputs affect outputs. Used for controller design, prediction, and optimization.'),
('22222222-2222-2222-2222-222222222222', 37, 'Describe an Articulated Robot.', 'Rotary joints (like human arm), human-arm-like appearance. 5-6 degrees of freedom. Used for welding, painting, assembly, material handling.'),
('22222222-2222-2222-2222-222222222222', 38, 'Describe a SCARA Robot.', 'Selective Compliance Assembly Robot Arm. Two parallel horizontal rotary joints plus vertical linear motion. Fast, precise for pick-and-place and assembly. Good for PCB assembly.'),
('22222222-2222-2222-2222-222222222222', 39, 'Describe a Cartesian Robot.', 'Three linear axes (X, Y, Z) perpendicular to each other. Gantry-type structure. Used for CNC machines, 3D printing, heavy part transfer. Simple kinematics.'),
('22222222-2222-2222-2222-222222222222', 40, 'Describe a Parallel Robot (Delta Robot).', 'Multiple arms connected to a common platform. High speed, high acceleration. Used in pick-and-place, food handling, pharmaceutical applications.'),
('22222222-2222-2222-2222-222222222222', 41, 'Describe a Cylindrical Coordinate Robot.', 'Combines rotating column with linear vertical and radial motion. Intermediate between cylindrical and Cartesian. Used in machine tending.'),
('22222222-2222-2222-2222-222222222222', 42, 'Describe a Spherical Coordinate Robot.', 'Rotatable arm rotating in spherical coordinates. Less common, used in specialized applications.'),
('22222222-2222-2222-2222-222222222222', 43, 'What is Robot Kinematics?', 'Mathematical relationship between joint angles and end-effector position and orientation. Forward kinematics: joint angles → position. Inverse kinematics: position → joint angles.'),
('22222222-2222-2222-2222-222222222222', 44, 'What is Robot Dynamics?', 'Study of forces and torques needed to produce motion. Includes inertia, friction, gravity effects. Important for joint motor sizing and control.'),
('22222222-2222-2222-2222-222222222222', 45, 'What is Robot Workspace?', 'The volume of space that the end-effector can reach. Limited by arm length and joint ranges. Important for task planning.'),
('22222222-2222-2222-2222-222222222222', 46, 'What is Robot Repeatability?', 'Ability to return to the same position and orientation. Typical values: 0.1-0.5mm. Different from accuracy (how close to programmed position).'),
('22222222-2222-2222-2222-222222222222', 47, 'What is Robot End-Effector?', 'Tool attached to robot wrist. Types: gripper (parallel or adhesive), welding torch, painting gun, force-torque sensor. Application-specific.'),
('22222222-2222-2222-2222-222222222222', 48, 'What is Robot Payload?', 'Maximum weight the robot can safely manipulate. Depends on arm strength and control system. Specified by manufacturer.'),
('22222222-2222-2222-2222-222222222222', 49, 'What is a Vision Sensor in Robotics?', 'Camera (CMOS or CCD) capturing images for object recognition, tracking, quality inspection, visual servoing. Enables flexible automation and adaptive control.'),
('22222222-2222-2222-2222-222222222222', 50, 'What is an Ultrasonic Sensor in Robotics?', 'Emits high-frequency sound waves and measures echo time-to-flight for distance. Used for obstacle avoidance, navigation, and safe operation.'),
('22222222-2222-2222-2222-222222222222', 51, 'What is a Force/Torque Sensor in Robotics?', 'Uses strain gauges to measure forces and moments applied to wrist. Essential for assembly tasks, grinding, force-controlled deburring. Enables tactile feedback.'),
('22222222-2222-2222-2222-222222222222', 52, 'What is an IMU in Robotics?', 'Inertial Measurement Unit combining accelerometers and gyroscopes (magnetometer optional). Measures linear acceleration and angular velocity. Essential for mobile/walking robots.'),
('22222222-2222-2222-2222-222222222222', 53, 'What is a Proximity Sensor in Robotics?', 'Inductive: detects metallic objects via magnetic field. Capacitive: detects conductive/dielectric objects via electric field. Used for end-of-travel, presence detection.'),
('22222222-2222-2222-2222-222222222222', 54, 'What is LIDAR?', 'Light Detection and Ranging. Uses laser to scan environment and build 3D maps. Critical for autonomous navigation and obstacle avoidance in robots.'),
('22222222-2222-2222-2222-222222222222', 55, 'What is Robot Calibration?', 'Process of measuring and correcting position/orientation errors in robot coordinates. Improves accuracy. Done periodically for high-precision applications.'),
('22222222-2222-2222-2222-222222222222', 56, 'What is Collaborative Robot (Cobot)?', 'Robot designed to work safely alongside humans. Force-limited (max ~150N), compliant, with safety sensors. Used in assembly, packaging, collaborative manufacturing.'),
('22222222-2222-2222-2222-222222222222', 57, 'What is Mobile Robot?', 'Robot that can navigate and move in environment. Uses wheels or legs. Equipped with sensors for localization and obstacle avoidance. Used in warehouses, exploration.'),
('22222222-2222-2222-2222-222222222222', 58, 'What is Autonomous Robot?', 'Robot making decisions based on sensor input without constant human guidance. Uses AI, machine learning. Operates independently in predefined or complex environments.'),
('22222222-2222-2222-2222-222222222222', 59, 'What is a Humanoid Robot?', 'Robot designed to resemble and mimic human form and behavior. Two arms, two legs, human-like head. Used in research, service, companion applications.'),
('22222222-2222-2222-2222-222222222222', 60, 'What is Boolean Algebra in PLC Programming?', 'Mathematical logic using AND, OR, NOT, XOR operations on binary variables (true/false). Forms basis of ladder logic and digital logic design.'),
('22222222-2222-2222-2222-222222222222', 61, 'What is Truth Table?', 'Tabular representation showing output for all input combinations. Example: AND gate has 4 rows (00=0, 01=0, 10=0, 11=1). Used to verify logic design.'),
('22222222-2222-2222-2222-222222222222', 62, 'What is De Morgan Law in Boolean Algebra?', 'NOT(A AND B) = NOT A OR NOT B, and NOT(A OR B) = NOT A AND NOT B. Used to simplify Boolean expressions and ladder logic.'),
('22222222-2222-2222-2222-222222222222', 63, 'What is Combinational Logic?', 'Output depends only on present inputs (no memory). Examples: AND, OR, NOT gates. Simpler than sequential logic but no state memory.'),
('22222222-2222-2222-2222-222222222222', 64, 'What is Sequential Logic?', 'Output depends on present inputs AND past history (has memory). Examples: flip-flops, counters, state machines. Used in process sequences.'),
('22222222-2222-2222-2222-222222222222', 65, 'What is a Flip-Flop in Digital Logic?', 'Memory element storing one bit (0 or 1). SR (Set-Reset), D (Data), JK, T (Toggle) types. Forms basis of counters and state machines.'),
('22222222-2222-2222-2222-222222222222', 66, 'What is a Counter in Digital Logic?', 'Sequential circuit that counts pulses. Binary counter increments with each clock pulse. Used for timing, frequency division, event counting in PLCs.'),
('22222222-2222-2222-2222-222222222222', 67, 'What is a Multiplexer?', 'Digital circuit selecting one of many inputs and routing to output. Selection determined by control lines. Used in data routing and signal selection.'),
('22222222-2222-2222-2222-222222222222', 68, 'What is a Decoder?', 'Circuit converting binary input to one-of-many active outputs. Example: 2-to-4 decoder converts 2-bit input to 4 outputs. Used in address decoding.'),
('22222222-2222-2222-2222-222222222222', 69, 'What is a State Machine?', 'Sequential logic system with defined states and transitions. Moves between states based on input conditions. Used in PLC programming for sequential processes.'),
('22222222-2222-2222-2222-222222222222', 70, 'What is PLC Output Types?', 'Digital (on/off, relay, transistor), analog (0-10V, 4-20mA). Digital: fast, simple. Analog: continuous control of speed, position.'),
('22222222-2222-2222-2222-222222222222', 71, 'What is PLC Input Types?', 'Digital (24V DC switches), analog (4-20mA transmitters, 0-10V sensors). Isolated inputs prevent noise coupling.'),
('22222222-2222-2222-2222-222222222222', 72, 'What is Analog-to-Digital Conversion (ADC)?', 'Converts continuous analog signal to discrete digital values. Resolution (bits) affects accuracy. 8-bit = 256 levels, 12-bit = 4096 levels.'),
('22222222-2222-2222-2222-222222222222', 73, 'What is Digital-to-Analog Conversion (DAC)?', 'Converts discrete digital values back to continuous analog signal. Used to drive analog actuators from digital controllers.'),
('22222222-2222-2222-2222-222222222222', 74, 'What is Sampling Theorem?', 'Digital signal must sample at rate > 2 times signal frequency to avoid aliasing. Sampling rate fs > 2fmax. Critical for data acquisition systems.'),
('22222222-2222-2222-2222-222222222222', 75, 'What is Aliasing in Digital Systems?', 'High-frequency components incorrectly represented as lower frequencies due to insufficient sampling rate. Causes erroneous digital signal. Prevention: low-pass filter before sampling.'),
('22222222-2222-2222-2222-222222222222', 76, 'What is Quantization Error?', 'Error between actual analog value and nearest digital level. Smaller for higher ADC resolution. Causes noise in digital signal.'),
('22222222-2222-2222-2222-222222222222', 77, 'What is Input Impedance?', 'Resistance presented by input circuit. High impedance (>>1MΩ) minimizes loading effect on signal source. Critical for sensor interfaces.'),
('22222222-2222-2222-2222-222222222222', 78, 'What is Output Impedance?', 'Resistance presented by output circuit. Low impedance (<<1Ω) allows driving external loads without voltage drop. Important for actuator control.'),
('22222222-2222-2222-2222-222222222222', 79, 'What is Electrical Noise in Control Systems?', 'Unwanted electrical signals degrading measurement accuracy. Sources: switching, motors, high-voltage lines. Prevention: shielding, filtering, grounding.'),
('22222222-2222-2222-2222-222222222222', 80, 'What is EMI (Electromagnetic Interference)?', 'Unwanted electromagnetic signals disrupting operation. High-frequency noise from switching supplies and RF sources. Prevention: shielding, ferrite filters.'),
('22222222-2222-2222-2222-222222222222', 81, 'What is Grounding in Industrial Systems?', 'Connection to common reference potential. Proper grounding reduces noise, improves safety. Star-point grounding minimizes ground loops.'),
('22222222-2222-2222-2222-222222222222', 82, 'What is Shielding in Sensor Cables?', 'Conductive layer around signal wire absorbing EMI. Shield connected to ground at one point to prevent ground loops. Critical for low-level signals.'),
('22222222-2222-2222-2222-222222222222', 83, 'What is Filtering in Control Systems?', 'Removing unwanted frequency components from signal. Low-pass filter: removes high-frequency noise. High-pass filter: removes DC drift. Affects phase and magnitude.'),
('22222222-2222-2222-2222-222222222222', 84, 'What is Nyquist Frequency?', 'Half the sampling frequency. Highest frequency that can be represented in digital signal. Fs/2. Sampling below this causes aliasing.'),
('22222222-2222-2222-2222-222222222222', 85, 'What is Pole Placement Control?', 'Design technique placing closed-loop poles at desired locations in s-plane. Achieved via state feedback. Allows direct specification of response characteristics.'),
('22222222-2222-2222-2222-222222222222', 86, 'What is Observer Design?', 'Creating a system model that estimates unmeasurable states from measured outputs. Used with state feedback for control of systems without full state measurement.'),
('22222222-2222-2222-2222-222222222222', 87, 'What is Kalman Filter?', 'Optimal estimation algorithm combining measurement and system model. Estimates system state from noisy measurements. Used in control and signal processing.'),
('22222222-2222-2222-2222-222222222222', 88, 'What is LQR (Linear Quadratic Regulator)?', 'Optimal control technique minimizing weighted sum of state error and control effort. Automatically generates optimal controller gains. Balances performance and energy use.'),
('22222222-2222-2222-2222-222222222222', 89, 'What is Stability Margins (GM and PM)?', 'Measures of how close system is to instability. Positive GM and PM indicate stable system. Industry standard: GM > 6 dB, PM > 30 degrees.'),
('22222222-2222-2222-2222-222222222222', 90, 'What is Bode Gain Crossover Frequency?', 'Frequency ωgc where magnitude = 1 (0 dB). Phase margin measured at this frequency. Approximately bandwidth of system.'),
('22222222-2222-2222-2222-222222222222', 91, 'What is Bode Phase Crossover Frequency?', 'Frequency ωpc where phase = -180 degrees. Gain margin measured at this frequency. For stability: magnitude must be < 1 at this frequency.'),
('22222222-2222-2222-2222-222222222222', 92, 'What is -3dB Bandwidth?', 'Frequency where magnitude drops to -3dB (70.7% of DC value). Indicator of system speed. Higher bandwidth = faster response.'),
('22222222-2222-2222-2222-222222222222', 93, 'What is System Resonance?', 'Frequency at which system response is maximum due to dynamic amplification. Second-order underdamped systems have resonance peak. Must be controlled for stability.'),
('22222222-2222-2222-2222-222222222222', 94, 'What is Magnitude Plot in Bode Diagram?', 'Vertical axis: 20 log10(|G(jω)|) in decibels. Horizontal axis: log ω (rad/s). Straight lines with slopes ±20 dB/decade per pole/zero.'),
('22222222-2222-2222-2222-222222222222', 95, 'What is Phase Plot in Bode Diagram?', 'Vertical axis: phase in degrees. Horizontal axis: log ω (rad/s). Each pole contributes -90 degrees, each zero +90 degrees at asymptotes.'),
('22222222-2222-2222-2222-222222222222', 96, 'What is Slope of Asymptotic Bode Plot?', '20(Z-P) dB/decade where Z = zeros, P = poles in that frequency range. Pole: -20 dB/decade, zero: +20 dB/decade.'),
('22222222-2222-2222-2222-222222222222', 97, 'What is Logarithmic Magnitude (dB)?', 'Logarithmic scale: 20 log10(M). Ratio of 10:1 = 20 dB, 2:1 ≈ 6 dB, 100:1 = 40 dB. Allows plotting wide range of magnitudes.'),
('22222222-2222-2222-2222-222222222222', 98, 'What is Root Locus?', 'Graphical plot showing how closed-loop poles move in s-plane as gain K varies (0 to ∞). Locus starts at open-loop poles, ends at zeros or infinity.'),
('22222222-2222-2222-2222-222222222222', 99, 'What are Root Locus Rules?', '1) Starts at poles. 2) Ends at zeros or infinity. 3) Symmetric about real axis. 4) Real-axis segments left of odd pole+zero count. 5) Asymptotes at (2q+1)180/(P-Z).'),
('22222222-2222-2222-2222-222222222222', 100, 'What is Breakaway Point in Root Locus?', 'Point where two branches meet on real axis (pole splitting). Found by dK/ds = 0. Indicates transition from two real poles to complex pair.'),
('22222222-2222-2222-2222-222222222222', 101, 'What is Departure Angle in Root Locus?', 'Angle at which locus leaves a pole (complex). Computed as 180 + (angle sum from zeros) - (angle sum from other poles). Determines locus direction.'),
('22222222-2222-2222-2222-222222222222', 102, 'What is Arrival Angle in Root Locus?', 'Angle at which locus arrives at a zero (complex). Computed as (angle sum from poles) - (angle sum from other zeros). Opposite sign of departure angle.'),
('22222222-2222-2222-2222-222222222222', 103, 'What is Centroid of Asymptotes in Root Locus?', 'Point where asymptotes intersect on real axis. Formula: σ = (Σpoles - Σzeros)/(# poles - # zeros). Center of locus.'),
('22222222-2222-2222-2222-222222222222', 104, 'What is Imaginary Axis Crossover in Root Locus?', 'Points where locus crosses imaginary axis, marking transition from stable to unstable. Found using Routh array with characteristic equation.'),
('22222222-2222-2222-2222-222222222222', 105, 'What is Dominant Pole?', 'Pole closest to imaginary axis in LHP. Controls transient response speed. Faster poles have smaller influence.'),
('22222222-2222-2222-2222-222222222222', 106, 'What is Pole Clustering?', 'Multiple poles at same location. Increases system order without changing fundamental dynamics. Can occur from cascading identical blocks.'),
('22222222-2222-2222-2222-222222222222', 107, 'What is Zero Location Effect?', 'Zero adds phase lead, improving transient response. Zero in RHP causes non-minimum phase behavior (initial reverse). Important in controller design.'),
('22222222-2222-2222-2222-222222222222', 108, 'Describe Hydraulic Valve Principle.', 'Pressurized fluid flows through variable orifice controlled by spool. Solenoid, manual, or pilot pressure moves spool. Flow rate: Q = Cd A √(2ΔP/ρ). Regulates actuator speed.'),
('22222222-2222-2222-2222-222222222222', 109, 'What is Proportional Solenoid Valve?', 'Solenoid current proportional to desired spool position. Allows continuous control without switching. Used for proportional flow control.'),
('22222222-2222-2222-2222-222222222222', 110, 'What is Directional Control Valve?', 'Routes fluid to different ports controlling actuator direction. 4/3 valve: 4 ports, 3 positions. Essential in hydraulic systems.'),
('22222222-2222-2222-2222-222222222222', 111, 'What is Pressure Relief Valve?', 'Limits maximum system pressure. Opens when pressure exceeds set value, venting excess fluid. Safety critical component.'),
('22222222-2222-2222-2222-222222222222', 112, 'What is Flow Control Valve?', 'Limits maximum flow rate regardless of pressure. Uses needle valve or compensator. Protects system from excessive speed.'),
('22222222-2222-2222-2222-222222222222', 113, 'What is Check Valve?', 'One-way valve allowing flow in one direction only. Prevents backflow. Common in pump discharge and actuator lines.'),
('22222222-2222-2222-2222-222222222222', 114, 'What is Accumulator in Hydraulic Systems?', 'Energy storage device holding pressurized fluid. Used for pressure surge absorption, energy recovery. Types: bladder, piston, diaphragm.'),
('22222222-2222-2222-2222-222222222222', 115, 'What is Viscosity Index?', 'Measure of oil viscosity change with temperature. Higher VI means more stable viscosity over temperature range. Important for hydraulic fluid selection.'),
('22222222-2222-2222-2222-222222222222', 116, 'What is Cavitation in Hydraulic Systems?', 'Formation of vapor bubbles in low-pressure regions. Causes noise, erosion, system damage. Prevention: proper line sizing, maintain inlet pressure.'),
('22222222-2222-2222-2222-222222222222', 117, 'What is Hydraulic Pump?', 'Device converting mechanical power to fluid pressure/flow. Positive displacement pump: consistent flow. Centrifugal pump: variable flow, lower pressure.'),
('22222222-2222-2222-2222-222222222222', 118, 'What is Hydraulic Motor?', 'Converts fluid pressure/flow into mechanical rotation. Torque proportional to pressure, speed to flow rate. Used in power-demanding applications.'),
('22222222-2222-2222-2222-222222222222', 119, 'What is Hydraulic Cylinder?', 'Converts fluid pressure into linear motion. Double-acting: push-pull. Single-acting: push only. Controlled by directional valve.'),
('22222222-2222-2222-2222-222222222222', 120, 'What is Pneumatic Valve?', 'Controls compressed air flow. Solenoid actuated. Types: 2/2 (on-off), 3/2 (direction change), 5/2 (double action), 5/3 (double action with center).'),
('22222222-2222-2222-2222-222222222222', 121, 'What is Pneumatic Cylinder?', 'Converts compressed air to linear motion. Single-acting: return by spring. Double-acting: push-pull both directions. Lower power than hydraulic.'),
('22222222-2222-2222-2222-222222222222', 122, 'What is Air Regulator?', 'Controls and stabilizes air pressure in pneumatic system. Reduces supply pressure to operational level. Includes pressure gauge.'),
('22222222-2222-2222-2222-222222222222', 123, 'What is Pneumatic Pressure?', 'Typical industrial: 0.8-0.9 MPa (8-9 bar). Lower than hydraulic (210-280 bar). Lower power but faster, cleaner operation.'),
('22222222-2222-2222-2222-222222222222', 124, 'What is Pneumatic Actuator Advantage?', '1) Fast response. 2) Safe (non-flammable, sparkless). 3) Clean (no fluid leakage). 4) Simple, low cost. 5) Easy maintenance.'),
('22222222-2222-2222-2222-222222222222', 125, 'What is Pneumatic Actuator Disadvantage?', '1) Compressible (affects control precision). 2) Lower power than hydraulic. 3) Requires air dryer, filter. 4) More energy loss.'),
('22222222-2222-2222-2222-222222222222', 126, 'Define Air Quality in Pneumatics.', 'Cleanliness and dryness essential. Contamination causes valve jamming, actuator stiction. ISO 4406: 16/14/11 (acceptable), 18/16/13 (standard).'),
('22222222-2222-2222-2222-222222222222', 127, 'What is FRL Unit (Filter-Regulator-Lubricator)?', 'Prepares compressed air for pneumatic system. Filter: removes particles. Regulator: maintains pressure. Lubricator: adds light oil for smooth operation.'),
('22222222-2222-2222-2222-222222222222', 128, 'What is Quick Disconnect in Pneumatics?', 'Coupling allowing rapid connection/disconnection without air loss. Essential for equipment changes, maintenance.'),
('22222222-2222-2222-2222-222222222222', 129, 'What is Pilot Pressure?', 'Low-pressure signal controlling large flow valve. Amplifies control signal. Example: pilot-operated relief valve.'),
('22222222-2222-2222-2222-222222222222', 130, 'What is Bleed Air in Pneumatic Systems?', 'Continuous small air flow to maintain pressure, reduce responsiveness lag. Balances energy vs response speed.'),
('22222222-2222-2222-2222-222222222222', 131, 'What is Solenoid in Control Valve?', 'Electromagnet converting electrical signal to mechanical motion. Controls valve spool position. Response time: 10-100 milliseconds typically.'),
('22222222-2222-2222-2222-222222222222', 132, 'What is Spring Return in Actuator?', 'Spring automatically returns actuator to neutral position when command is removed. Safety feature in pneumatic and hydraulic systems.'),
('22222222-2222-2222-2222-222222222222', 133, 'What is Actuator Response Time?', 'Time from command signal to desired position. Pneumatic: 10-50ms. Hydraulic: 50-200ms. Electric: 100-500ms. Pneumatic fastest.'),
('22222222-2222-2222-2222-222222222222', 134, 'What is Pressure Drop across Valve?', 'Loss of pressure due to valve resistance. Higher flow → larger drop. Must account in system design. Typical: 0.5-2 bar.'),
('22222222-2222-2222-2222-222222222222', 135, 'What is Rated Flow (Qrated)?', 'Maximum continuous flow valve can handle at rated pressure drop. Design should stay below 80-90% rated flow for reliability and response.');
